   1→//! File discovery with glob/ignore support.
   2→//!
   3→//! Walks a directory tree to find source files for analysis, respecting
   4→//! `.gitignore`, `.shatterignore`, and user-specified include/exclude patterns.
   5→//! Also discovers convention-based setup files for the multi-level setup lifecycle.
   6→
   7→use std::collections::HashMap;
   8→use std::path::{Path, PathBuf};
   9→
  10→use globset::{Glob, GlobSet, GlobSetBuilder};
  11→
  12→/// Supported language, detected by file extension.
  13→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
  14→pub enum Language {
  15→    TypeScript,
  16→    Go,
  17→    Rust,
  18→}
  19→
  20→impl Language {
  21→    /// Detect language from a file extension string (without the leading dot).
  22→    pub fn from_extension(ext: &str) -> Option<Self> {
  23→        match ext {
  24→            "ts" | "tsx" => Some(Language::TypeScript),
  25→            "go" => Some(Language::Go),
  26→            "rs" => Some(Language::Rust),
  27→            _ => None,
  28→        }
  29→    }
  30→
  31→    /// Returns the language name as used in the crypto registry TOML.
  32→    pub fn as_registry_str(&self) -> &'static str {
  33→        match self {
  34→            Language::TypeScript => "typescript",
  35→            Language::Go => "go",
  36→            Language::Rust => "rust",
  37→        }
  38→    }
  39→}
  40→
  41→/// Options controlling which files are discovered.
  42→#[derive(Debug, Clone)]
  43→pub struct DiscoveryOptions {
  44→    /// Glob patterns for files to include (e.g. `["**/*.ts"]`). Empty means all supported files.
  45→    pub include_patterns: Vec<String>,
  46→    /// Glob patterns for files to exclude (e.g. `["**/vendor/**"]`).
  47→    pub exclude_patterns: Vec<String>,
  48→    /// Whether to respect `.gitignore` files.
  49→    pub respect_gitignore: bool,
  50→    /// Maximum directory traversal depth. `None` means unlimited.
  51→    pub max_depth: Option<usize>,
  52→}
  53→
  54→impl Default for DiscoveryOptions {
  55→    fn default() -> Self {
  56→        Self {
  57→            include_patterns: vec![],
  58→            exclude_patterns: vec![],
  59→            respect_gitignore: true,
  60→            max_depth: None,
  61→        }
  62→    }
  63→}
  64→
  65→/// Default directory/file patterns that are always excluded.
  66→const DEFAULT_EXCLUDES: &[&str] = &[
  67→    "**/node_modules/**",
  68→    "**/vendor/**",
  69→    "**/dist/**",
  70→    "**/target/**",
  71→    "**/__tests__/**",
  72→    "**/*.test.ts",
  73→    "**/*_test.go",
  74→];
  75→
  76→/// Errors that can occur during file discovery.
  77→#[derive(Debug, thiserror::Error)]
  78→pub enum DiscoveryError {
  79→    #[error("I/O error: {0}")]
  80→    Io(#[from] std::io::Error),
  81→    #[error("invalid glob pattern '{pattern}': {source}")]
  82→    InvalidPattern {
  83→        pattern: String,
  84→        source: globset::Error,
  85→    },
  86→}
  87→
  88→/// Discover source files under `root`, returning each file's path and detected language.
  89→///
  90→/// Applies default exclusions, user-specified include/exclude patterns,
  91→/// `.gitignore` rules (if `options.respect_gitignore` is true), and
  92→/// `.shatterignore` rules.
  93→pub fn discover_files(
  94→    root: &Path,
  95→    options: &DiscoveryOptions,
  96→) -> Result<Vec<(PathBuf, Language)>, DiscoveryError> {
  97→    let include_set = build_glob_set(&options.include_patterns)?;
  98→    let exclude_set = build_glob_set(&options.exclude_patterns)?;
  99→    let default_exclude_set = build_glob_set(
 100→        &DEFAULT_EXCLUDES.iter().map(|s| (*s).to_string()).collect::<Vec<_>>(),
 101→    )?;
 102→
 103→    let ignore_matcher = if options.respect_gitignore {
 104→        load_ignore_file(&root.join(".gitignore"))
 105→    } else {
 106→        None
 107→    };
 108→    let shatter_ignore_matcher = load_ignore_file(&root.join(".shatterignore"));
 109→
 110→    let mut results = Vec::new();
 111→    walk_dir(root, root, 0, &WalkConfig {
 112→        include_set: &include_set,
 113→        exclude_set: &exclude_set,
 114→        default_exclude_set: &default_exclude_set,
 115→        ignore_matcher: ignore_matcher.as_ref(),
 116→        shatter_ignore_matcher: shatter_ignore_matcher.as_ref(),
 117→        max_depth: options.max_depth,
 118→    }, &mut results)?;
 119→
 120→    results.sort_by(|a, b| a.0.cmp(&b.0));
 121→    Ok(results)
 122→}
 123→
 124→struct WalkConfig<'a> {
 125→    include_set: &'a Option<GlobSet>,
 126→    exclude_set: &'a Option<GlobSet>,
 127→    default_exclude_set: &'a Option<GlobSet>,
 128→    ignore_matcher: Option<&'a GlobSet>,
 129→    shatter_ignore_matcher: Option<&'a GlobSet>,
 130→    max_depth: Option<usize>,
 131→}
 132→
 133→fn walk_dir(
 134→    base: &Path,
 135→    dir: &Path,
 136→    depth: usize,
 137→    config: &WalkConfig<'_>,
 138→    results: &mut Vec<(PathBuf, Language)>,
 139→) -> Result<(), DiscoveryError> {
 140→    let entries = match std::fs::read_dir(dir) {
 141→        Ok(e) => e,
 142→        Err(e) if e.kind() == std::io::ErrorKind::NotFound => return Ok(()),
 143→        Err(e) => return Err(DiscoveryError::Io(e)),
 144→    };
 145→
 146→    for entry in entries {
 147→        let entry = entry?;
 148→        let path = entry.path();
 149→        let relative = path.strip_prefix(base).unwrap_or(&path);
 150→
 151→        if path.is_dir() {
 152→            // Respect max_depth if set
 153→            if let Some(max) = config.max_depth
 154→                && depth >= max
 155→            {
 156→                continue;
 157→            }
 158→            // Check if directory is excluded by default patterns
 159→            // For directory matching, append a trailing slash sentinel
 160→            let dir_pattern_path = PathBuf::from(format!("{}/sentinel", relative.display()));
 161→            if let Some(set) = config.default_exclude_set
 162→                && set.is_match(&dir_pattern_path)
 163→            {
 164→                continue;
 165→            }
 166→            if let Some(set) = config.exclude_set
 167→                && set.is_match(&dir_pattern_path)
 168→            {
 169→                continue;
 170→            }
 171→            if let Some(set) = config.ignore_matcher
 172→                && set.is_match(&dir_pattern_path)
 173→            {
 174→                continue;
 175→            }
 176→            if let Some(set) = config.shatter_ignore_matcher
 177→                && set.is_match(&dir_pattern_path)
 178→            {
 179→                continue;
 180→            }
 181→            walk_dir(base, &path, depth + 1, config, results)?;
 182→            continue;
 183→        }
 184→
 185→        // Check default excludes
 186→        if let Some(set) = config.default_exclude_set
 187→            && set.is_match(relative)
 188→        {
 189→            continue;
 190→        }
 191→
 192→        // Check user excludes
 193→        if let Some(set) = config.exclude_set
 194→            && set.is_match(relative)
 195→        {
 196→            continue;
 197→        }
 198→
 199→        // Check .gitignore
 200→        if let Some(set) = config.ignore_matcher
 201→            && set.is_match(relative)
 202→        {
 203→            continue;
 204→        }
 205→
 206→        // Check .shatterignore
 207→        if let Some(set) = config.shatter_ignore_matcher
 208→            && set.is_match(relative)
 209→        {
 210→            continue;
 211→        }
 212→
 213→        // Detect language
 214→        let ext = path.extension().and_then(|e| e.to_str());
 215→        let language = ext.and_then(Language::from_extension);
 216→        let Some(language) = language else {
 217→            continue;
 218→        };
 219→
 220→        // Check user includes (if specified, file must match at least one)
 221→        if let Some(set) = config.include_set
 222→            && !set.is_match(relative)
 223→        {
 224→            continue;
 225→        }
 226→
 227→        results.push((path, language));
 228→    }
 229→
 230→    Ok(())
 231→}
