 480→    /// Create a file at the given path, creating parent directories as needed.
 481→    fn create_file(base: &Path, relative: &str) {
 482→        let path = base.join(relative);
 483→        if let Some(parent) = path.parent() {
 484→            fs::create_dir_all(parent).expect("create dirs");
 485→        }
 486→        fs::write(&path, "// placeholder").expect("write file");
 487→    }
